#include <bits/stdc++.h>
using namespace std;
const int maxn=1e2+5;
int n,m,a[maxn][maxn],vis[maxn][maxn];
void dfs(int s,int x) {
	for(int i=1; i<=n; i++) {
		if(a[x][i]&&!vis[s][i]) {
			vis[s][i]=1;
			dfs(s,i);
		}
	}
}
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n;
	for(int i=1; i<=n; i++)
		for(int j=1; j<=n; j++)
			cin>>a[i][j];
	for(int i=1; i<=n; i++)
		dfs(i,i);
	for(int i=1; i<=n; i++,cout<<"\n")
		for(int j=1; j<=n; j++)
			cout<<vis[i][j]<<" ";
	return 0;
}
